  hs_meeting_enabled: null,
  questions: [ "propertyOwnershipStatus", "roofSlope" ],
  __i18n_lang: ""
}
]
```

I want you to create a CSV for me with questions listed as rows, and market as columns.
I'll help you create a CSV format where questions are rows and markets are columns. I'll put an "x" where a question exists for that market. Here's the CSV format:

```
Question,Norway,Poland,Portugal,Sweden
eaveHeight,,x,,
gridPhase,,,x,
installationPlacement,x,,x,
intentionToBuy,,x,x,
interestingPurchaseModel,,,x,
monthlyEnergyConsumption,,x,,
monthlyEnergySpend,,,x,
mountingSurface,x,x,,
preferredContactTime,,,x,
propertyOwnershipStatus,,,,x
roofSlope,,x,,x
yearlyEnergyConsumption,x,,,
```

This CSV shows:
- Each unique question as a row
- Each market as a column
- An "x" where a question is present for that market
- Empty cells where questions aren't used in that market

You can copy this directly into a .csv file, and it will render properly in spreadsheet software.
perfect, now write a script that produce this CSV

Here's a JavaScript script that will produce the CSV format from your input array:

```javascript
function generateQuestionsCSV(data) {
    // Get all unique questions
    const allQuestions = new Set();
    data.forEach(item => {
        item.questions.forEach(question => {
            allQuestions.add(question);
        });
    });

    // Get all markets
    const markets = data.map(item => item.market);

    // Sort questions and markets alphabetically
    const sortedQuestions = Array.from(allQuestions).sort();
    const sortedMarkets = markets.sort();

    // Create header row
    let csv = `Question,${sortedMarkets.join(',')}\n`;

    // Create question rows
    sortedQuestions.forEach(question => {
        let row = [question];

        // For each market, check if the question exists
        sortedMarkets.forEach(market => {
            const marketData = data.find(item => item.market === market);
            const hasQuestion = marketData.questions.includes(question);
            row.push(hasQuestion ? 'x' : '');
        });

        csv += row.join(',') + '\n';
    });

    return csv;
}

// Your input data
const data = [
    {
        _updatedAt: "2024-05-30T13:39:31Z",
        hs_meeting_enabled: false,
        questions: [
            "installationPlacement",
            "mountingSurface",
            "yearlyEnergyConsumption"
        ],
        __i18n_lang: null,
        market: "Norway"
    },
    // ... rest of your data ...
];

// Generate and log the CSV
const csv = generateQuestionsCSV(data);
console.log(csv);
```

This script:

1. Creates a `generateQuestionsCSV` function that takes your data array as input
2. Extracts all unique questions into a Set
3. Gets all markets from the data
4. Sorts both questions and markets alphabetically
5. Creates the CSV header row with "Question" and all markets
6. For each question:
   - Creates a row starting with the question
   - Checks each market to see if it contains that question
   - Adds an "x" if the question exists for that market, or an empty string if it doesn't
7. Joins everything with commas and newlines to create proper CSV format

To use this script, you can either:
- Save the CSV to a file using Node.js:
```javascript
const fs = require('fs');
fs.writeFileSync('questions.csv', generateQuestionsCSV(data));
```

- Or in a browser, create a downloadable file:
```javascript
function downloadCSV(csv) {
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = window.URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.setAttribute('href', url);
    a.setAttribute('download', 'questions.csv');
    a.click();
}

downloadCSV(generateQuestionsCSV(data));
```

This will generate exactly the same CSV format as shown in the previous answer, which you can then open in any spreadsheet software.
